Fl_Double_Window* MainPanel::make_panel() {
  { main_window = new Fl_Double_Window(300, 525, "FLUID");
    main_window->color(FL_BACKGROUND2_COLOR);
    main_window->selection_color(FL_DARK1);
    main_window->callback((Fl_Callback*)cb_main_window, (void*)(this));
    { main_menubar = new Fl_Menu_Bar(0, 0, 300, 25);
      { Fl_Menu_Item* o = &menu_main_menubar[4];
        o->label(Fluid.history.short_path[0]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[5];
        o->label(Fluid.history.short_path[1]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[6];
        o->label(Fluid.history.short_path[2]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[7];
        o->label(Fluid.history.short_path[3]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[8];
        o->label(Fluid.history.short_path[4]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[9];
        o->label(Fluid.history.short_path[5]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[10];
        o->label(Fluid.history.short_path[6]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[11];
        o->label(Fluid.history.short_path[7]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[12];
        o->label(Fluid.history.short_path[8]);
      }
      { Fl_Menu_Item* o = &menu_main_menubar[13];
        o->label(Fluid.history.short_path[9]);
      }
      main_menubar->menu(menu_main_menubar);
      main_menubar->global();
    } // Fl_Menu_Bar* main_menubar
    { widget_browser = new Widget_Browser(0, 25, 300, 500);
      widget_browser->box(FL_FLAT_BOX);
      widget_browser->color(FL_BACKGROUND2_COLOR);
      widget_browser->selection_color(FL_SELECTION_COLOR);
      widget_browser->labeltype(FL_NORMAL_LABEL);
      widget_browser->labelfont(0);
      widget_browser->labelsize(14);
      widget_browser->labelcolor(FL_FOREGROUND_COLOR);
      widget_browser->align(Fl_Align(FL_ALIGN_BOTTOM));
      widget_browser->when(FL_WHEN_RELEASE_ALWAYS);
      Fl_Group::current()->resizable(widget_browser);
    } // Widget_Browser* widget_browser
    main_window->size_range(280, 200);
    main_window->end();
  } // Fl_Double_Window* main_window
  return main_window;
}

