/**
 Build the panel, don't show it yet.
*/
void MainPanel::build() {
//~fl~0~0000~e34a750b~~
  if (main_window == nullptr) {
    make_panel();
  }
//~fl~1~e74e~444c7294~~
}

/**
 Build if needed and show the panel.
*/
void MainPanel::show() {
//~fl~0~0000~d600e79d~~
  build();
  main_window->show();
//~fl~1~9938~653b75be~~
}

/**
 Hide the panel and retain for later.
*/
void MainPanel::hide() {
//~fl~0~0000~e29f0ce0~~
  if (main_window) {
    main_window->hide();
  }
//~fl~1~ea3d~7d15f02b~~
}
